const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 1 / 10;

const applyFirstInsuranceSurcharge = (premium: number): number =>
  premium + premium * FIRST_INSURANCE_SURCHARGE_RATE;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

export const quote = (items: Array<{ type: string }>, customer: unknown, contractNumber: number): number => {
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.includes(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  let totalPremium = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.includes(item.type) && componentCounts[item.type] === BLOCK_SIZE) {
      continue;
    }
    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
    totalPremium += applyFirstInsuranceSurcharge(basePremium);
  }

  for (const type of COMPONENT_TYPES) {
    if (componentCounts[type] === BLOCK_SIZE) {
      totalPremium += applyFirstInsuranceSurcharge(BLOCK_PREMIUM);
    }
  }

  return Math.ceil(totalPremium) + PROCESSING_FEE;
};

export function claim(): unknown {
  return undefined;
}

